445	// BuildArgs constructs the argument array for a harness invocation.
446	// Exported for testing.
447	func BuildArgs(h harnessConfig, opts RunOptions, model string) []string {
448		// Use BaseArgs if set, fall back to legacy Args for compatibility.
449		base := h.BaseArgs
450		if base == nil {
451			base = h.Args
452		}
453		args := append([]string{}, base...)
454	
455		// Append permission-specific args.
456		if h.PermissionArgs != nil {
457			level := opts.Permissions
458			if level == "" {
459				level = "safe"
460			}
461			if extra, ok := h.PermissionArgs[level]; ok {
462				args = append(args, extra...)
463			}
464		}
465	
466		if opts.WorkDir != "" && h.WorkDirFlag != "" {
467			args = append(args, h.WorkDirFlag, opts.WorkDir)
468		}
469		if model != "" && h.ModelFlag != "" {
470			args = append(args, h.ModelFlag, model)
471		}
472		if opts.Effort != "" && h.EffortFlag != "" {
473			if h.EffortFormat != "" {
474				args = append(args, h.EffortFlag, fmt.Sprintf(h.EffortFormat, opts.Effort))
475			} else {
476				args = append(args, h.EffortFlag, opts.Effort)
477			}
478		}
479		if h.PromptMode == "arg" {
480			args = append(args, opts.Prompt)
481		}
482		return args
483	}
